"use client";
// Mirrors React-template PieChart.jsx — piechart-style-01, 02 (SVG radial rings)

import { useEffect, useRef, useState } from "react";

export interface PieChartItem {
  title: string;
  percentage: number;
  color?: string;
}

interface Props {
  theme?: "piechart-style-01" | "piechart-style-02";
  data: PieChartItem[];
}

const R = 44;
const CIRCUMFERENCE = 2 * Math.PI * R;
const SIZE = 110;
const CX = SIZE / 2;

function Ring({ item, animated }: { item: PieChartItem; animated: boolean }) {
  const color = item.color || "var(--primary)";
  const offset = animated ? CIRCUMFERENCE * (1 - item.percentage / 100) : CIRCUMFERENCE;

  return (
    <svg className="pc-svg" width={SIZE} height={SIZE} viewBox={`0 0 ${SIZE} ${SIZE}`}>
      <circle className="pc-track" cx={CX} cy={CX} r={R} strokeWidth="8" />
      <circle
        className="pc-fill"
        cx={CX} cy={CX} r={R}
        strokeWidth="8"
        stroke={color}
        strokeDasharray={`${CIRCUMFERENCE} ${CIRCUMFERENCE}`}
        strokeDashoffset={offset}
      />
      <text className="pc-label-text" x={CX} y={CX} textAnchor="middle" dominantBaseline="central">
        {animated ? `${item.percentage}%` : ""}
      </text>
    </svg>
  );
}

function AnimatedRing({ item, theme }: { item: PieChartItem; theme: Props["theme"] }) {
  const ref = useRef<HTMLDivElement>(null);
  const [animated, setAnimated] = useState(false);

  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) { setAnimated(true); obs.disconnect(); }
    }, { threshold: 0.3 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);

  if (theme === "piechart-style-02") {
    return (
      <div ref={ref} className="pc-item">
        <Ring item={item} animated={animated} />
        <div className="pc-info">
          <div className="pc-title">{item.title}</div>
          <div className="pc-pct">{item.percentage}% completion</div>
        </div>
      </div>
    );
  }

  return (
    <div ref={ref} className="pc-item">
      <Ring item={item} animated={animated} />
      <div className="pc-title">{item.title}</div>
    </div>
  );
}

export default function PieChart({ theme = "piechart-style-01", data }: Props) {
  const cls = theme === "piechart-style-02" ? "pc-02" : "pc-01";
  return (
    <div className={cls}>
      {data.map((item, i) => <AnimatedRing key={i} item={item} theme={theme} />)}
    </div>
  );
}
