"use client";
// Mirrors React-template FancyText.jsx — fancy-text-style-01 (gradient), 02 (marquee), 03 (typewriter)

import { useEffect, useState } from "react";

interface Props {
  theme?: "fancy-text-style-01" | "fancy-text-style-02" | "fancy-text-style-03" | "fancy-text-style-04" | "fancy-text-style-05";
  text?: string;
  strings?: string[];
  className?: string;
}

export default function FancyText({ theme = "fancy-text-style-01", text = "SyncCore ERP", strings = [], className = "" }: Props) {
  if (theme === "fancy-text-style-01") {
    return <span className={`ft-gradient ${className}`}>{text}</span>;
  }

  if (theme === "fancy-text-style-02") {
    const items = strings.length > 0 ? strings : [text, text, text, text];
    return (
      <div className={`ft-marquee-wrap ${className}`}>
        <div className="ft-marquee">
          {/* duplicate for seamless loop */}
          {[...items, ...items].map((s, i) => (
            <span key={i} className="text-[--dark] font-bold text-2xl">{s}</span>
          ))}
        </div>
      </div>
    );
  }

  if (theme === "fancy-text-style-04") {
    return <WordCycle strings={strings.length > 0 ? strings : [text]} wrapClass="ft-rotate-wrap" wordClass="ft-rotate-word" className={className} />;
  }

  if (theme === "fancy-text-style-05") {
    return <WordCycle strings={strings.length > 0 ? strings : [text]} wrapClass="ft-slide-wrap" wordClass="ft-slide-word" className={className} />;
  }

  // style-03: typewriter
  return <Typewriter strings={strings.length > 0 ? strings : [text]} className={className} />;
}

function WordCycle({ strings, wrapClass, wordClass, className }: { strings: string[]; wrapClass: string; wordClass: string; className: string }) {
  const [idx, setIdx] = useState(0);
  const [key, setKey] = useState(0);

  useEffect(() => {
    const id = setInterval(() => {
      setIdx((i) => (i + 1) % strings.length);
      setKey((k) => k + 1);
    }, 2400);
    return () => clearInterval(id);
  }, [strings]);

  return (
    <span className={`${wrapClass} ${className}`}>
      <span key={key} className={wordClass}>{strings[idx]}</span>
    </span>
  );
}

function Typewriter({ strings, className }: { strings: string[]; className: string }) {
  const [display, setDisplay] = useState("");
  const [si, setSi] = useState(0);
  const [ci, setCi] = useState(0);
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    const current = strings[si];
    const delay = deleting ? 60 : 100;

    const id = setTimeout(() => {
      if (!deleting) {
        setDisplay(current.slice(0, ci + 1));
        if (ci + 1 === current.length) {
          setTimeout(() => setDeleting(true), 1800);
        } else {
          setCi((c) => c + 1);
        }
      } else {
        setDisplay(current.slice(0, ci - 1));
        if (ci - 1 === 0) {
          setDeleting(false);
          setSi((s) => (s + 1) % strings.length);
          setCi(0);
        } else {
          setCi((c) => c - 1);
        }
      }
    }, delay);

    return () => clearTimeout(id);
  }, [display, ci, deleting, si, strings]);

  return (
    <span className={`ft-typewriter ${className}`}>
      {display}
      <span className="ft-cursor" />
    </span>
  );
}
