"use client";
// Mirrors React-template Testimonials.jsx — testimonials-style-01 to 05

import { useState } from "react";

export interface TestimonialItem {
  content: string;
  name: string;
  designation?: string;
  img?: string;
  rating?: number;
  company?: string;
}

interface Props {
  theme?: "testimonials-style-01" | "testimonials-style-02" | "testimonials-style-03" | "testimonials-style-04" | "testimonials-style-05";
  data: TestimonialItem[];
  grid?: string;
  carousel?: boolean;
}

export default function Testimonials({ theme = "testimonials-style-01", data, grid = "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3", carousel = false }: Props) {
  if (carousel) return <CarouselMode theme={theme} data={data} />;

  return (
    <div className={`grid ${grid} gap-8`}>
      {data.map((item, i) => <Card key={i} theme={theme} item={item} />)}
    </div>
  );
}

function Stars({ n }: { n: number }) {
  return <span>{"★".repeat(n)}{"☆".repeat(5 - n)}</span>;
}

function Card({ theme, item }: { theme: Props["theme"]; item: TestimonialItem }) {
  if (theme === "testimonials-style-01") {
    return (
      <div className="testi-01">
        <div className="t-quote">"</div>
        <p className="t-content">{item.content}</p>
        <div className="t-author">
          {item.img && <img src={item.img} alt={item.name} />}
          <div>
            <div className="t-name">{item.name}</div>
            <div className="t-role">{item.designation}</div>
          </div>
        </div>
      </div>
    );
  }
  if (theme === "testimonials-style-02") {
    return (
      <div className="testi-02">
        {item.img && <img src={item.img} alt={item.name} />}
        <div>
          <p className="t-content">{item.content}</p>
          <div className="t-name">{item.name}</div>
          <div className="t-role">{item.designation}</div>
        </div>
      </div>
    );
  }
  if (theme === "testimonials-style-03") {
    return (
      <div>
        <div className="testi-03">
          <p className="t-content">{item.content}</p>
          <div className="t-author">
            {item.img && <img src={item.img} alt={item.name} />}
            <div>
              <div className="t-name">{item.name}</div>
              <div className="t-role">{item.designation}</div>
            </div>
          </div>
        </div>
      </div>
    );
  }
  if (theme === "testimonials-style-04") {
    return (
      <div className="testi-04">
        {item.rating && <div className="t-stars"><Stars n={item.rating} /></div>}
        <p className="t-content">{item.content}</p>
        <div className="t-author">
          {item.img && <img src={item.img} alt={item.name} />}
          <div>
            <div className="t-name">{item.name}</div>
            <div className="t-role">{item.designation}</div>
          </div>
        </div>
      </div>
    );
  }
  // style-05
  return (
    <div className="testi-05">
      {item.rating && <div className="t-stars"><Stars n={item.rating} /></div>}
      <p className="t-content">{item.content}</p>
      <div className="t-author">
        {item.img && <img src={item.img} alt={item.name} />}
        <div>
          <div className="t-name">{item.name}</div>
          <div className="t-role">{item.designation}</div>
        </div>
      </div>
    </div>
  );
}

function CarouselMode({ theme, data }: { theme: Props["theme"]; data: TestimonialItem[] }) {
  const [idx, setIdx] = useState(0);
  const prev = () => setIdx((idx - 1 + data.length) % data.length);
  const next = () => setIdx((idx + 1) % data.length);

  return (
    <div className="relative">
      <div className="max-w-2xl mx-auto px-10">
        <Card theme={theme} item={data[idx]} />
      </div>
      <button onClick={prev} className="absolute left-0 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-white border border-[--border] flex items-center justify-center hover:bg-[--primary] hover:text-white hover:border-[--primary] transition-all">←</button>
      <button onClick={next} className="absolute right-0 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-white border border-[--border] flex items-center justify-center hover:bg-[--primary] hover:text-white hover:border-[--primary] transition-all">→</button>
      <div className="flex justify-center gap-2 mt-6">
        {data.map((_, i) => (
          <button key={i} onClick={() => setIdx(i)} className={`w-2 h-2 rounded-full transition-all ${i === idx ? "bg-[--primary] w-5" : "bg-[--border]"}`} />
        ))}
      </div>
    </div>
  );
}
