"use client";
// Mirrors React-template MessageBox.jsx — message-box-01, 02

import { useState } from "react";

type Variant = "success" | "info" | "warning" | "danger";

interface Props {
  theme?: "message-box-01" | "message-box-02";
  variant: Variant;
  message: string;
  dismissible?: boolean;
}

const ICONS: Record<Variant, string> = {
  success: "✓",
  info:    "ℹ",
  warning: "⚠",
  danger:  "✕",
};

export default function MessageBox({ theme = "message-box-01", variant, message, dismissible = false }: Props) {
  const [visible, setVisible] = useState(true);
  if (!visible) return null;

  const themeClass = theme === "message-box-02" ? "msg-box-02" : "msg-box-01";

  return (
    <div className={`msg-box ${themeClass} ${variant}`} role="alert">
      <div className="flex items-start gap-2">
        <span className="font-bold flex-shrink-0">{ICONS[variant]}</span>
        <span dangerouslySetInnerHTML={{ __html: message }} />
      </div>
      {dismissible && (
        <button className="msg-close" onClick={() => setVisible(false)} aria-label="Dismiss">
          ×
        </button>
      )}
    </div>
  );
}
