"use client";
// Mirrors React-template TextSlider.jsx — text-slider-style-01, 02, 03

import { useCallback, useEffect, useState } from "react";

export interface TextSlideItem {
  heading: string;
  subheading?: string;
  description?: string;
}

interface Props {
  theme?: "text-slider-style-01" | "text-slider-style-02" | "text-slider-style-03";
  data: TextSlideItem[];
  autoPlay?: boolean;
}

export default function TextSlider({ theme = "text-slider-style-01", data, autoPlay = true }: Props) {
  const [active, setActive] = useState(0);
  const total = data.length;

  const next = useCallback(() => setActive((p) => (p + 1) % total), [total]);
  const prev = () => setActive((p) => (p - 1 + total) % total);

  useEffect(() => {
    if (!autoPlay) return;
    const id = setInterval(next, 4500);
    return () => clearInterval(id);
  }, [autoPlay, next]);

  const cls = theme === "text-slider-style-03" ? "ts-03" : theme === "text-slider-style-02" ? "ts-02" : "ts-01";

  return (
    <div className={`ts-wrap ${cls}`}>
      <div className="ts-track" style={{ transform: `translateX(-${active * 100}%)` }}>
        {data.map((item, i) => (
          <div key={i} className="ts-slide">
            {item.subheading && <div className="ts-sub">{item.subheading}</div>}
            <div className="ts-heading">{item.heading}</div>
            {item.description && theme === "text-slider-style-01" && (
              <div className="ts-desc">{item.description}</div>
            )}
          </div>
        ))}
      </div>

      <div className="ts-nav">
        <button className="ts-arrow" onClick={prev} aria-label="Previous">←</button>
        {data.map((_, i) => (
          <button
            key={i}
            className={`ts-dot ${i === active ? "active" : ""}`}
            onClick={() => setActive(i)}
            aria-label={`Slide ${i + 1}`}
          />
        ))}
        <button className="ts-arrow" onClick={next} aria-label="Next">→</button>
      </div>
    </div>
  );
}
