"use client";
// Mirrors React-template TeamCarousel.jsx

import { brandIcon } from "@/components/icons/brandIcons";
import { useCallback, useEffect, useState } from "react";
import type { TeamMember } from "./Team";

interface Props {
  data: TeamMember[];
  theme?: "team-style-01" | "team-style-02" | "team-style-03";
  visibleCount?: number;
}

const DEFAULT_SOCIAL = [
  { icon: brandIcon("facebook"), link: "#", label: "Facebook" },
  { icon: brandIcon("linkedin"), link: "#", label: "LinkedIn" },
  { icon: brandIcon("twitter"), link: "#", label: "Twitter" },
];

export default function TeamCarousel({ data, theme = "team-style-01", visibleCount = 4 }: Props) {
  const [active, setActive] = useState(0);
  const total = data.length;
  const next = useCallback(() => setActive((p) => (p + 1) % total), [total]);
  const prev = () => setActive((p) => (p - 1 + total) % total);

  useEffect(() => {
    const id = setInterval(next, 5000);
    return () => clearInterval(id);
  }, [next]);

  return (
    <div>
      <div className="carousel-track-wrap">
        <div className="carousel-track" style={{ transform: `translateX(-${active * 100}%)` }}>
          {data.map((member, i) => (
            <div key={i} className="carousel-slide" style={{ width: `${100 / Math.min(visibleCount, total)}%`, minWidth: "200px", padding: "0 0.5rem" }}>
              <MemberCard member={member} theme={theme} />
            </div>
          ))}
        </div>
      </div>

      <div className="slider-nav">
        <button className="slider-prev" onClick={prev}>←</button>
        {data.map((_, i) => (
          <button key={i} className={`slider-dot ${i === active ? "active" : ""}`} onClick={() => setActive(i)} />
        ))}
        <button className="slider-next" onClick={next}>→</button>
      </div>
    </div>
  );
}

function MemberCard({ member, theme }: { member: TeamMember; theme: Props["theme"] }) {
  const social = member.social || DEFAULT_SOCIAL;

  if (theme === "team-style-03") {
    return (
      <div className="team-03">
        <img src={member.img} alt={member.name} />
        <div className="t-overlay" style={{ background: "linear-gradient(to top, rgba(0,85,212,0.9) 0%, transparent 60%)" }}>
          <div className="t-info">
            <h5>{member.name}</h5>
            <div className="t-role">{member.designation}</div>
            <div className="t-social">{social.map((s, i) => <a key={i} href={s.link} aria-label={s.label || "Social link"}>{s.icon}</a>)}</div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="team-01 text-center">
      <div className="t-img"><img src={member.img} alt={member.name} /></div>
      <h5>{member.name}</h5>
      <div className="t-role">{member.designation}</div>
      <div className="t-social">{social.map((s, i) => <a key={i} href={s.link} aria-label={s.label || "Social link"}>{s.icon}</a>)}</div>
    </div>
  );
}
