"use client";
// Mirrors React-template ImageGallery.jsx — image-gallery-01, 02, 03

import { useState } from "react";

export interface GalleryItem {
  img: string;
  title?: string;
}

interface Props {
  theme?: "image-gallery-01" | "image-gallery-02" | "image-gallery-03";
  data: GalleryItem[];
  overlay?: string;
}

export default function ImageGallery({ theme = "image-gallery-02", data, overlay = "rgba(0,85,212,0.8)" }: Props) {
  const [lightbox, setLightbox] = useState<string | null>(null);

  const cls = theme === "image-gallery-01" ? "ig-01" : theme === "image-gallery-03" ? "ig-03" : "ig-02";

  return (
    <>
      <div className={cls}>
        {data.map((item, i) => (
          <div key={i} className="ig-item" onClick={() => setLightbox(item.img)}>
            <img src={item.img} alt={item.title || ""} loading="lazy" />
            <div className="ig-overlay" style={{ background: overlay }}>
              <span className="ig-overlay-icon">🔍</span>
            </div>
            {theme === "image-gallery-03" && item.title && (
              <div className="ig-caption">{item.title}</div>
            )}
          </div>
        ))}
      </div>

      {lightbox && (
        <div className="ig-lightbox" onClick={() => setLightbox(null)}>
          <button className="ig-lightbox-close">×</button>
          <img src={lightbox} alt="" onClick={(e) => e.stopPropagation()} />
        </div>
      )}
    </>
  );
}
