"use client";

import { useState } from "react";
import { Play, Sparkles, X } from "lucide-react";

type ModalType = "simple" | "contact" | "subscription" | "video";

interface Props {
  triggers?: { label: string; type: ModalType }[];
}

const DEFAULT_TRIGGERS: { label: string; type: ModalType }[] = [
  { label: "Simple Modal", type: "simple" },
  { label: "Contact Form", type: "contact" },
  { label: "Subscription", type: "subscription" },
  { label: "Video Modal", type: "video" },
];

export default function Modal({ triggers = DEFAULT_TRIGGERS }: Props) {
  const [open, setOpen] = useState<ModalType | null>(null);

  return (
    <>
      <div className="flex flex-wrap gap-3">
        {triggers.map((t) => (
          <button
            key={t.type}
            className="btn btn-sm btn-primary"
            onClick={() => setOpen(t.type)}
          >
            {t.label}
          </button>
        ))}
      </div>

      {open && (
        <div className="modal-backdrop" onClick={() => setOpen(null)}>
          <div className="modal-box" onClick={(e) => e.stopPropagation()}>
            <button className="modal-close" onClick={() => setOpen(null)} aria-label="Close modal">
              <X aria-hidden="true" />
            </button>

            {open === "simple" && (
              <div className="text-center">
                <div className="modal-icon">
                  <Sparkles aria-hidden="true" />
                </div>
                <h3 className="modal-title">Hello there!</h3>
                <p className="modal-text">This is a simple modal. It can contain any content you need.</p>
                <button className="btn btn-primary" onClick={() => setOpen(null)}>Continue</button>
              </div>
            )}

            {open === "contact" && (
              <div>
                <h3 className="modal-title" style={{ marginBottom: "1.5rem" }}>Get in Touch</h3>
                <form className="modal-form" onSubmit={(e) => e.preventDefault()}>
                  {(["Name", "Email"] as const).map((field) => (
                    <div key={field}>
                      <label className="modal-label">{field}</label>
                      <input type={field === "Email" ? "email" : "text"} className="modal-input" />
                    </div>
                  ))}
                  <div>
                    <label className="modal-label">Message</label>
                    <textarea rows={3} className="modal-textarea" />
                  </div>
                  <button type="submit" className="btn btn-primary w-full">Send Message</button>
                </form>
              </div>
            )}

            {open === "subscription" && (
              <div className="text-center">
                <h3 className="modal-title">Stay in the loop</h3>
                <p className="modal-text">Get the latest updates and resources delivered to your inbox.</p>
                <div className="modal-email-row">
                  <input type="email" className="modal-input" placeholder="Enter your email" style={{ flex: 1 }} />
                  <button className="btn btn-primary" style={{ borderRadius: 0 }}>Subscribe</button>
                </div>
              </div>
            )}

            {open === "video" && (
              <div className="modal-video-bg">
                <div className="text-center">
                  <div className="modal-play-btn">
                    <Play aria-hidden="true" />
                  </div>
                  <p style={{ color: "rgba(255,255,255,.5)", fontSize: ".8rem", margin: 0 }}>Video Modal Demo</p>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </>
  );
}
