"use client";
// Mirrors React-template CountDown.jsx — countdown-style-01, 02, 03

import { useEffect, useState } from "react";

interface Props {
  theme?: "countdown-style-01" | "countdown-style-02" | "countdown-style-03";
  targetDate: string;
}

interface TimeLeft { days: number; hours: number; minutes: number; seconds: number; }

function getTimeLeft(target: string): TimeLeft {
  const diff = Math.max(0, new Date(target).getTime() - Date.now());
  return {
    days:    Math.floor(diff / 86400000),
    hours:   Math.floor((diff % 86400000) / 3600000),
    minutes: Math.floor((diff % 3600000)  / 60000),
    seconds: Math.floor((diff % 60000)    / 1000),
  };
}

const UNITS = ["days", "hours", "minutes", "seconds"] as const;

export default function CountDown({ theme = "countdown-style-01", targetDate }: Props) {
  const [time, setTime] = useState<TimeLeft>(() => getTimeLeft(targetDate));

  useEffect(() => {
    const id = setInterval(() => setTime(getTimeLeft(targetDate)), 1000);
    return () => clearInterval(id);
  }, [targetDate]);

  const cls = theme === "countdown-style-03" ? "cd-03" : theme === "countdown-style-02" ? "cd-02" : "cd-01";

  return (
    <div className={cls}>
      {UNITS.map((unit) => (
        <div key={unit} className="cd-unit">
          {theme === "countdown-style-03" ? (
            <div className="cd-ring">
              <span className="cd-num">{String(time[unit]).padStart(2, "0")}</span>
            </div>
          ) : (
            <span className="cd-num">{String(time[unit]).padStart(2, "0")}</span>
          )}
          <span className="cd-label">{unit}</span>
        </div>
      ))}
    </div>
  );
}
