"use client";
// Mirrors React-template ProgressBar.jsx

import { useEffect, useRef, useState } from "react";

export interface ProgressItem {
  title: string;
  percentage: number;
  color?: string;
}

interface Props {
  data: ProgressItem[];
  primaryColor?: string;
}

export default function ProgressBar({ data, primaryColor = "var(--primary)" }: Props) {
  return (
    <div className="space-y-5">
      {data.map((item, i) => <Bar key={i} item={item} primaryColor={item.color || primaryColor} />)}
    </div>
  );
}

function Bar({ item, primaryColor }: { item: ProgressItem; primaryColor: string }) {
  const [width, setWidth] = useState(0);
  const ref = useRef<HTMLDivElement>(null);
  const started = useRef(false);

  useEffect(() => {
    const observer = new IntersectionObserver(([e]) => {
      if (e.isIntersecting && !started.current) {
        started.current = true;
        setTimeout(() => setWidth(item.percentage), 100);
      }
    }, { threshold: 0.3 });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, [item.percentage]);

  return (
    <div ref={ref} className="progress-bar-wrap">
      <div className="progress-bar-label">
        <span>{item.title}</span>
        <span>{width}%</span>
      </div>
      <div className="progress-bar-track">
        <div className="progress-bar-fill" style={{ width: `${width}%`, background: primaryColor }} />
      </div>
    </div>
  );
}
