"use client";
// Mirrors React-template Video.jsx — video-style-01 (modal), video-style-02 (inline embed)

import { useState } from "react";
import { Play, X } from "lucide-react";

interface Props {
  theme?: "video-style-01" | "video-style-02";
  videoId: string;
  poster?: string;
  title?: string;
}

export default function Video({ theme = "video-style-01", videoId, poster, title }: Props) {
  const [open, setOpen] = useState(false);
  const src = `https://www.youtube.com/embed/${videoId}?autoplay=1`;
  const thumb = poster || `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg`;

  if (theme === "video-style-02") {
    return (
      <div className="video-embed">
        <iframe
          src={`https://www.youtube.com/embed/${videoId}`}
          title={title || "Video"}
          allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
          allowFullScreen
        />
      </div>
    );
  }

  return (
    <>
      <div className="video-box">
        <img src={thumb} alt={title || "Video thumbnail"} />
        <div className="video-overlay" />
        <button className="v-play-btn btn-sonar" onClick={() => setOpen(true)} aria-label="Play video">
          <Play aria-hidden="true" />
        </button>
      </div>

      {open && (
        <div className="video-modal" onClick={() => setOpen(false)}>
          <div className="video-modal-inner" onClick={(e) => e.stopPropagation()}>
            <button className="video-modal-close" onClick={() => setOpen(false)} aria-label="Close video">
              <X aria-hidden="true" />
            </button>
            <iframe
              src={src}
              title={title || "Video"}
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
              allowFullScreen
            />
          </div>
        </div>
      )}
    </>
  );
}
